const b = $input.first().json.body ?? $input.first().json;
const p = b.perfil ?? {};
const prompt = `Monte um plano alimentar diário BRASILEIRO para:
${JSON.stringify(p)}
Gosta de: ${(b.gosta ?? []).join(', ') || 'sem preferência'}
Não come: ${(b.naoGosta ?? []).join(', ') || 'nada'}
Refeições por dia: ${b.refeicoesDia ?? 4}

Use alimentos comuns no Brasil (valores nutricionais da tabela TACO). Meta calórica: ${p.metaCalorias} kcal (respeite ±5%). Distribua proteína ao longo do dia.

Responda APENAS com JSON válido neste formato exato, sem markdown:
{"objetivo":"...","totalKcal":0,"macros":{"prot":0,"carb":0,"gord":0,"fibra":0},"refeicoes":[{"nome":"Café da manhã","horario":"07:00","itens":[{"alimento":"...","qtd":"100g","kcal":0,"prot":0,"carb":0,"gord":0}]}],"recomendacoes":["...","Este plano não substitui um nutricionista."]}`;
return [{ json: { prompt } }];

const texto = $input.first().json.content?.[0]?.text ?? '{}';
const limpo = texto.replace(/```json|```/g, '').trim();
let plano = null;
try { plano = JSON.parse(limpo); } catch (e) { plano = null; }
return [{ json: { plano } }];
